var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그러니까...... 자네들 이름이 릴리와 리코리스라고 했던가?","JPN":"それで……名前はリリーとリコリスと言ったか？","ENG":"Hmm... So your names are Lily and Lycoris?","TWN":"所以……你們叫莉莉和莉克麗絲對嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그렇습니다, 교수님.","JPN":"はい、教授。","ENG":"Yes, Professor.","TWN":"是的，教授。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>맨션</color>의 취향은 듣던 대로 꽤나 고상하군. 기르는 사냥개들에게 꽃 이름을 붙여 주다니.","JPN":"<color=#ffd34c>マンション</color>の好みは噂通りお上品だな。飼い犬に花の名前を付けるなんて。","ENG":"The <color=#ffd34c>Mansion</color> seems to have a most sophisticated taste as its reputation says. Naming its hounds after flowers...","TWN":"<color=#ffd34c>曼森</color>的品味如傳聞一樣高尚。竟然給飼養的獵犬取花的名字。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"잔소리 그만하고 안내나 하지 그래?","JPN":"無駄話はそれくらいにしてさっさと案内して。","ENG":"Alright, enough small talk. Why don't you just show us the way?","TWN":"廢話少說，趕緊帶路。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"우린 당신이랑 노닥거리러 온 거 아니거든?","JPN":"私はあんたと仲良くおしゃべりしに来たわけじゃないの。","ENG":"We're not here to goof around with you.","TWN":"我們可不是來和你閒聊的。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"흠. 누가 젊은 친구들 아니랄까 봐 열정이 넘치는군.","JPN":"ほう。さすが若者はやる気満々でいいな。","ENG":"Hah. Young and passionate, I see.","TWN":"唔。果然是年輕人啊，血氣方剛的。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"거의 다 왔네. 조금만 더 참게나.","JPN":"あと少しで着くからあせる必要はない。","ENG":"We're almost there. Have a little patience.","TWN":"快到了，再堅持一下。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"자, 여길세. 데몬 타입 침식체가 출몰했던 침식 재난 구역의 한복판이지.","JPN":"さあ、ここだ。デーモンタイプ侵食体が出没した侵食災害区域の中心だ。","ENG":"Here we are. We're in the middle of the disaster zone where the Demon-Type C.O.s appeared.","TWN":"到了，這裡就是惡魔型侵蝕體出沒的侵蝕災難區域的中心。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"재난이 터졌을 때 소유주가 사망하는 바람에 행정상으로 유령처럼 붕 뜬 곳이 됐어.","JPN":"災害が起きた時に所有者が死亡して、行政上の都合で今は空き地同然なのさ。","ENG":"The owner was killed during the incident, so this place is an administrative no-man's land.","TWN":"災難來臨的時候業主死了，這裡就成了幽靈城市。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"용병들이 기웃거릴 일도 드물 테니 아지트로 안성맞춤일 걸세.","JPN":"傭兵が来ることもめったにないと思うから、アジトとしてはうってつけの場所だろう。","ENG":"Even mercenaries stay away from here. It will be a perfect hideout for you.","TWN":"傭兵也不會來這裡，所以最適合做秘密基地了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"흥, 돈 받고 이딴 폐허를 소개해 주는 거야?","JPN":"ふん、人からもらった金でこんな廃墟を紹介するの？","ENG":"Hmpf. This is what we get for what we're paying you?","TWN":"哼，你收了錢就給我們介紹這種破地方？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"블랙 네트워크에서 솜씨 좋은 중계상이라고 하던데 별거 없네.","JPN":"ブラックネットワークで腕のいい仲介人と聞いたのに、大したことないわね。","ENG":"I heard you were one of the best brokers on the Dark Network, but I guess your reputation's exaggerated.","TWN":"什麼黑色網路裡有名的仲介商，我看也不過如此而已。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스. 불평 그만하고 저 분께 남은 대금을 넘겨 드리세요.","JPN":"リコリス、文句をいうのはそれくらいにして、その方に残金を支払ってください。","ENG":"Lycoris, stop complaining and issue him the remainder of the payment.","TWN":"莉克麗絲，別抱怨了，趕緊把剩下的錢給他吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐? 너 정말 여기서 지낼 생각이야?","JPN":"え？　リリーは本当にここでいいの？","ENG":"What? Are you seriously thinking of staying here?","TWN":"什麼？妳真的要選這裡？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"우리는 비합법적인 경로로 이 도시에 숨어들어 온 입장이에요.","JPN":"私たちは非合法のルートでこの都市に入った立場です。","ENG":"We snuck into this city through an illegal route.","TWN":"我們是通過非法途徑偷偷來到這個城市的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"눈에 띄는 숙소에서 지내다가 귀찮은 일을 만들면 마스터를 뵐 면목이 없습니다.","JPN":"人目の多い宿に泊まって面倒なことに巻き込まれたら、マスターに合わせる顔がないでしょう。","ENG":"We don't want to attract more attention than needed. What would the Master say?","TWN":"總不能住在顯眼的地方吧，萬一發生什麼麻煩事，我就沒臉見頭目了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"씨이......","JPN":"ちっ……","ENG":"Ugh...","TWN":"切……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};